parameters.query:
DROP TABLE docket_storage;

CREATE TABLE docket_storage (
  docket_id TEXT PRIMARY KEY,
  docket_summary TEXT,
  docket_title TEXT,
  created_at TIMESTAMP,
  objectid TEXT
);

SELECT DISTINCT docket_id
FROM comment_storage
ORDER BY docket_id;

SELECT STRING_AGG(comment_id || ': ' || comment_text, ' ')
FROM comment_storage
WHERE docket_id = '{{ $json.docket_id }}';

SELECT comment_id, comment_text
FROM comment_storage
WHERE docket_id = '{{ $json.docket_id }}';

